/**
 *
 * This function matches a given value to a predefined list of true and false values, including
 * English words. String comparisons are case insensitive.
 *
 * Returns `true` if the value is one of the following:
 * * `true`
 * * `1`
 * * `'1'`
 * * `'yes'`
 * * `'on'`
 * * `'true'`
 *
 * Returns `false` if the value is one of the following:
 * * `false`
 * * `0`
 * * `'0'`
 * * `'no'`
 * * `'off'`
 * * `'false'`
 *
 * Otherwise returns `undefined`.
 *
 * @deprecated `@splunk/ui-utils/boolean` is deprecated and will be removed in a future major version. Use `@splunk/splunk-utils/boolean` instead.
 * @param {Boolean|Number|String} value - The value to be evaluated.
 * @returns {Boolean|undefined}
 * @public
 */
export declare function normalizeBoolean(value: any): boolean | undefined;
